import{_ as e,a as t}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Safety/user-rate-limits.md","filePath":"ms-MY/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"ms-MY/Safety/user-rate-limits.md"};function n(o,a,u,p,m,h){return d(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits mengawal berapa kerap regular users atau visitors boleh upload files dari homepage. Ini membantu mengelakkan public upload pages daripada disalahgunakan.</p><p>Feature ini hanya mempengaruhi homepage uploads. Admin uploads dan uploads menggunakan API Tokens tidak dihadkan oleh user rate limits.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Buka admin panel, kemudian pergi ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+e+'" alt="User rate limit settings" loading="lazy"></p><h2 id="mengaktifkan-rate-limits" tabindex="-1">Mengaktifkan Rate Limits <a class="header-anchor" href="#mengaktifkan-rate-limits" aria-label="Permalink to &quot;Mengaktifkan Rate Limits&quot;">​</a></h2><p>Selepas <code>Enable Rate Limits</code> dihidupkan, ImgBed track recent uploads berdasarkan uploader IP address.</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>Sejauh mana upload records ke belakang akan dikira.</td></tr><tr><td>Max file count</td><td>20</td><td>Jumlah files maksimum yang dibenarkan dalam detection window.</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>Saiz maksimum untuk satu file.</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>Jumlah upload size maksimum dalam detection window.</td></tr></tbody></table><p>Contohnya, dengan 1.5 hour window, 20 files, 20 MB setiap file dan 200 MB total, uploads dari IP yang sama akan diblock apabila mana-mana configured limit dilebihi.</p><h2 id="excluding-file-types" tabindex="-1">Excluding File Types <a class="header-anchor" href="#excluding-file-types" aria-label="Permalink to &quot;Excluding File Types&quot;">​</a></h2><p><code>Excluded upload file types</code> menghalang regular users atau visitors daripada upload file categories yang dipilih.</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif dan image files seumpamanya</td></tr><tr><td>Videos</td><td>mp4, webm, mov dan video files seumpamanya</td></tr><tr><td>Audio</td><td>mp3, flac, wav dan audio files seumpamanya</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx dan document files seumpamanya</td></tr><tr><td>Other</td><td>Files di luar categories di atas, seperti zip, rar, exe, apk</td></tr></tbody></table><p>Secara default, tiada type dipilih, bermaksud ia allowed.</p><p>Klik type akan highlight type tersebut, bermaksud type itu blocked.</p><p>Jika <code>Other</code> dipilih, visitors yang upload zip atau rar files akan diblock dan diberitahu bahawa file type ini tidak disokong.</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>Apabila limit dicetuskan, users melihat message yang sepadan:</p><p><img src="'+t+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>File terlalu besar dan patut dicompress sebelum upload.</td></tr><tr><td>File type blocked</td><td>File type ini tidak disokong. Buang file tersebut dan cuba lagi.</td></tr><tr><td>Uploads too frequent</td><td>Recent uploads terlalu kerap, dengan retry time dipaparkan.</td></tr><tr><td>Total size too high</td><td>Recent total upload size terlalu tinggi, dengan retry time dipaparkan.</td></tr></tbody></table><h2 id="bila-patut-enable" tabindex="-1">Bila Patut Enable <a class="header-anchor" href="#bila-patut-enable" aria-label="Permalink to &quot;Bila Patut Enable&quot;">​</a></h2><p>Enable user rate limits jika upload homepage anda boleh diakses secara public.</p><p>Sebab biasa:</p><ul><li>Anda risau tentang scripted bulk uploads.</li><li>Anda mahu mengehadkan large visitor uploads.</li><li>Anda hanya mahu regular users upload images, bukan archives atau installers.</li><li>Anda mahu public upload kekal tersedia sambil mengawal resource usage.</li></ul><p>Jika site hanya untuk diri sendiri, atau hanya administrators boleh upload, anda boleh biarkan disabled.</p>',28)])])}const k=i(r,[["render",n]]);export{b as __pageData,k as default};
